
import base64
from io import BytesIO
from rembg import remove

from PIL import Image

# Function to decode Base64 string into an image
def base64_to_image(base64_string):
    image_data = base64.b64decode(base64_string)
    return Image.open(BytesIO(image_data))

# Function to encode an image back to Base64
def image_to_base64(image):
    buffered = BytesIO()
    image.save(buffered, format="PNG")  # Save as PNG to keep transparency
    return base64.b64encode(buffered.getvalue()).decode("utf-8")

# Example Base64 string (replace this with your actual Base64 string)
base64_string = ""  # Your Base64 data

# Convert Base64 to Image
image_input = base64_to_image(base64_string)

# Process the image with rembg
output_image = remove(image_input)

# Convert the output image back to Base64 (optional)
output_base64 = image_to_base64(output_image)

# Save the output image (if needed)
output_image.save("./output/output.png")

print("Background removed and saved!")


